### 생성할 파일 3: `src/layouts/UserLayout.jsx`

```jsx
import { useState } from 'react';
import { Outlet, useNavigate } from 'react-router-dom';
import { logout as logoutApi } from '@/features/auth/authApi';
import { useAuthStore } from '@/store/useAuthStore';
import { LayoutHeader } from './components/LayoutHeader';
import { UserSidebar } from './components/UserSidebar';
import { Breadcrumbs } from './Breadcrumbs';

export const UserLayout = () => {
    const navigate = useNavigate();
    const user = useAuthStore((state) => state.user);
    const logout = useAuthStore((state) => state.logout);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

    const handleLogout = async () => {
        try { await logoutApi(); } finally {
            logout();
            navigate('/login');
        }
    };

    return (
        <div className='min-h-screen bg-background text-foreground'>
            <LayoutHeader
                homeRoute='/app/home'
                mobileMenuOpen={mobileMenuOpen}
                onMobileMenuOpenChange={setMobileMenuOpen}
                onLogout={handleLogout}
                user={user}
                SidebarComponent={UserSidebar}
            />
            <div className='flex mt-[var(--nav-h)] min-h-[calc(100vh-var(--nav-h))]'>
                <aside className='hidden lg:flex flex-col shrink-0 bg-card border-r-[1.5px] border-border w-[var(--sidebar-w)] sticky top-[var(--nav-h)] h-[calc(100vh-var(--nav-h))] overflow-y-auto'>
                    <UserSidebar user={user} />
                </aside>
                <main className='flex-1 min-w-0 p-8 px-10'>
                    <div className='mb-7'><Breadcrumbs /></div>
                    <Outlet />
                </main>
            </div>
        </div>
    );
};
```

이 파일을 import할 파일: `src/app/router.jsx` (추후 수정 예정)

---

**중요:** `src/layouts/Breadcrumbs.jsx`가 실제로 존재하는지 먼저 Glob으로 확인하세요. 없으면 UserLayout에서 Breadcrumbs import와 사용 부분을 제거하고 생성하세요.

3개 파일 모두 생성 후 완료 여부를 알려주세요.

